class Solution {
    public int magicalString(int n) {
        if (n <= 0) {
            return 0;
        }
        int[] s = new int[n + 1];
        s[1] = 1;
        int i = 1, j = 2, count = 0;
        while (j <= n) {
            if (s[i] == 1) {
                s[j] = 2;
            } else {
                s[j] = 1;
            }
            j++;
            if (j > n) {
                break;
            }
            i++;
            count += s[i - 1];
        }
        return count;
    }
}
```
